"use client";

import { useState } from "react";
import {
  CreditCard,
  TrendingUp,
  TrendingDown,
  ArrowUpRight,
  ArrowDownLeft,
  Plus,
  Eye,
  EyeOff,
  Copy,
  Check,
  Wallet,
  Activity,
  Menu,
  Search,
  Filter,
  ArrowRight,
} from "lucide-react";
import Link from "next/link";
import DashboardSidebar from "@/components/DashboardSidebar";

interface Card {
  id: string;
  name: string;
  balance: number;
  cardNumber: string;
  expiryDate: string;
  status: "active" | "expired";
  spent: number;
  limit: number;
}

interface Transaction {
  id: string;
  type: "topup" | "payment";
  amount: number;
  description: string;
  date: string;
  status: "completed" | "pending";
  merchant?: string;
}

export default function Dashboard() {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [showBalance, setShowBalance] = useState(true);
  const [copiedCard, setCopiedCard] = useState<string | null>(null);

  const [cards] = useState<Card[]>([
    {
      id: "1",
      name: "Shopping Card",
      balance: 450.0,
      cardNumber: "4532 1234 5678 8901",
      expiryDate: "12/26",
      status: "active",
      spent: 550,
      limit: 1000,
    },
    {
      id: "2",
      name: "Subscription Card",
      balance: 25.5,
      cardNumber: "4532 1234 5678 2345",
      expiryDate: "03/27",
      status: "active",
      spent: 974.5,
      limit: 1000,
    },
    {
      id: "3",
      name: "Travel Card",
      balance: 890.0,
      cardNumber: "4532 1234 5678 3456",
      expiryDate: "09/26",
      status: "active",
      spent: 110,
      limit: 1000,
    },
  ]);

  const [transactions] = useState<Transaction[]>([
    {
      id: "1",
      type: "topup",
      amount: 500.0,
      description: "Bitcoin Deposit",
      date: "2024-12-09",
      status: "completed",
      merchant: "Bitcoin Network",
    },
    {
      id: "2",
      type: "payment",
      amount: -29.99,
      description: "Netflix Subscription",
      date: "2024-12-08",
      status: "completed",
      merchant: "Netflix",
    },
    {
      id: "3",
      type: "payment",
      amount: -45.0,
      description: "Amazon Purchase",
      date: "2024-12-07",
      status: "completed",
      merchant: "Amazon",
    },
    {
      id: "4",
      type: "payment",
      amount: -12.99,
      description: "Spotify Premium",
      date: "2024-12-06",
      status: "completed",
      merchant: "Spotify",
    },
    {
      id: "5",
      type: "payment",
      amount: -89.5,
      description: "Uber Rides",
      date: "2024-12-05",
      status: "completed",
      merchant: "Uber",
    },
  ]);

  const totalBalance = cards.reduce((sum, card) => sum + card.balance, 0);
  const totalSpent = cards.reduce((sum, card) => sum + card.spent, 0);

  const copyCardNumber = (cardNumber: string) => {
    const formattedNumber = cardNumber.replace(
      /(\d{4})\s(\d{4})\s(\d{4})\s(\d{4})/,
      "$1 **** **** $4"
    );
    navigator.clipboard.writeText(cardNumber);
    setCopiedCard(formattedNumber);
    setTimeout(() => setCopiedCard(null), 2000);
  };

  const maskCardNumber = (cardNumber: string) => {
    return cardNumber.replace(
      /(\d{4})\s(\d{4})\s(\d{4})\s(\d{4})/,
      "$1 **** **** $4"
    );
  };

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat("en-US", {
      style: "currency",
      currency: "USD",
    }).format(amount);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex">
      {/* Sidebar */}
      <DashboardSidebar
        isSidebarOpen={isSidebarOpen}
        setIsSidebarOpen={setIsSidebarOpen}
      />

      {/* Main Content */}
      <div className="flex-1 flex flex-col lg:ml-0 relative">
        {/* Header */}
        <header className="bg-white border-b border-gray-200">
          <div className="responsive-container">
            <div className="flex items-center justify-between h-16">
              <div className="flex items-center gap-4">
                <button
                  onClick={() => setIsSidebarOpen(true)}
                  className="lg:hidden p-2 bg-gray-100 hover:bg-gray-200 rounded-lg transition-colors"
                >
                  <Menu className="w-5 h-5 text-gray-700" />
                </button>
                <h1 className="text-xl font-semibold text-black">
                  Dashboard
                </h1>
              </div>

              <div className="flex items-center gap-4">
                <button
                  onClick={() => setShowBalance(!showBalance)}
                  className="p-2 bg-gray-100 hover:bg-gray-200 rounded-lg transition-colors"
                  aria-label="Toggle balance visibility"
                >
                  {showBalance ? (
                    <EyeOff className="w-5 h-5 text-gray-700" />
                  ) : (
                    <Eye className="w-5 h-5 text-gray-700" />
                  )}
                </button>
                <div className="w-10 h-10 bg-black rounded-lg flex items-center justify-center">
                  <span className="text-white font-bold text-sm">JD</span>
                </div>
              </div>
            </div>
          </div>
        </header>

        {/* Page Content */}
        <main className="flex-1 p-6 overflow-y-auto">
          {/* Welcome */}
          <div className="mb-8">
            <h2 className="text-2xl font-bold text-black mb-2">
              Welcome back, John
            </h2>
            <p className="text-sm text-gray-600">
              Your crypto empire awaits — here's a snapshot of your finances.
            </p>
          </div>

          {/* Stats Overview */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
            {/* Total Balance */}
            <div className="bg-white border border-gray-200 rounded-lg p-6">
              <div className="flex items-center justify-between mb-4">
                <div className="w-12 h-12 bg-gray-100 rounded-lg flex items-center justify-center">
                  <Wallet className="w-6 h-6 text-black" />
                </div>
                <div className="flex items-center gap-1 px-3 py-1 bg-gray-100 rounded-full">
                  <TrendingUp className="w-4 h-4 text-gray-700" />
                  <span className="text-gray-700 text-sm font-medium">
                    +12.5%
                  </span>
                </div>
              </div>
              <h3 className="text-sm mb-1 font-medium text-gray-600">
                Total Balance
              </h3>
              <p className="text-3xl font-bold text-black mb-2">
                {showBalance ? formatCurrency(totalBalance) : "••••••"}
              </p>
              <div className="w-full h-2 bg-gray-200 rounded-full overflow-hidden">
                <div className="h-full bg-black rounded-full transition-all duration-1000" style={{ width: "60%" }} />
              </div>
            </div>

            {/* Virtual Cards */}
            <div className="bg-white border border-gray-200 rounded-lg p-6">
              <div className="flex items-center justify-between mb-4">
                <div className="w-12 h-12 bg-gray-100 rounded-lg flex items-center justify-center">
                  <CreditCard className="w-6 h-6 text-black" />
                </div>
                <div className="flex items-center gap-1 px-3 py-1 bg-gray-100 rounded-full">
                  <Activity className="w-4 h-4 text-gray-700" />
                  <span className="text-gray-700 text-sm font-medium">
                    {cards.length} Active
                  </span>
                </div>
              </div>
              <h3 className="text-sm mb-1 font-medium text-gray-600">
                Virtual Cards
              </h3>
              <p className="text-3xl font-bold text-black mb-2">
                {cards.length}
              </p>
              <div className="flex items-center gap-2">
                {[...Array(cards.length)].map((_, i) => (
                  <div
                    key={i}
                    className="w-2 h-2 bg-black rounded-full"
                  ></div>
                ))}
              </div>
            </div>

            {/* Total Spent */}
            <div className="bg-white border border-gray-200 rounded-lg p-6">
              <div className="flex items-center justify-between mb-4">
                <div className="w-12 h-12 bg-gray-100 rounded-lg flex items-center justify-center">
                  <TrendingDown className="w-6 h-6 text-black" />
                </div>
                <div className="flex items-center gap-1 px-3 py-1 bg-gray-100 rounded-full">
                  <Activity className="w-4 h-4 text-gray-700" />
                  <span className="text-gray-700 text-sm font-medium">
                    This Month
                  </span>
                </div>
              </div>
              <h3 className="text-sm mb-1 font-medium text-gray-600">
                Total Spent
              </h3>
              <p className="text-3xl font-bold text-black mb-2">
                {showBalance ? formatCurrency(totalSpent) : "••••••"}
              </p>
              <div className="w-full h-2 bg-gray-200 rounded-full overflow-hidden">
                <div
                  className="h-full bg-black rounded-full transition-all duration-1000"
                  style={{
                    width: `${Math.min((totalSpent / 2000) * 100, 100)}%`,
                  }}
                />
              </div>
            </div>
          </div>

          {/* Cards Section */}
          <div className="mb-8">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-bold text-black">
                Your Virtual Cards
              </h2>
              <Link
                href="/dashboard/create-card"
                className="inline-flex items-center px-6 py-3 bg-black text-white font-medium rounded-lg hover:bg-gray-900 transition-colors"
              >
                <Plus className="w-5 h-5 mr-2" />
                Create New Card
              </Link>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {cards.map((card) => (
                <div key={card.id} className="bg-white border border-gray-200 rounded-lg overflow-hidden">
                  {/* Card Front */}
                  <div
                    className="relative p-6 h-48 flex flex-col"
                    style={{
                      background: "linear-gradient(135deg, #000000 0%, #262626 100%)",
                    }}
                  >
                    {/* Top Row */}
                    <div className="flex items-start justify-between mb-6">
                      <div>
                        <p className="text-white text-xs font-bold tracking-widest uppercase">
                          CREDIT
                        </p>
                      </div>
                      <div className="flex items-center gap-1">
                        <div className="w-2 h-2 bg-green-400 rounded-full"></div>
                        <span className="text-white/90 text-xs font-medium capitalize">
                          {card.status}
                        </span>
                      </div>
                    </div>

                    {/* Card Number */}
                    <div className="mb-auto">
                      <p className="text-white text-xl font-bold tracking-[0.2em] font-mono">
                        {maskCardNumber(card.cardNumber)}
                      </p>
                    </div>

                    {/* Bottom Row */}
                    <div className="flex items-end justify-between">
                      <div className="flex items-center gap-3">
                        <div className="bg-gradient-to-br from-yellow-300 to-yellow-500 w-11 h-9 rounded-lg flex items-center justify-center border border-yellow-200/50">
                          <CreditCard className="w-5 h-5 text-yellow-700/60" />
                        </div>
                        <div>
                          <p className="text-white/60 text-[9px] uppercase tracking-wider mb-0.5">
                            Card Holder
                          </p>
                          <p className="text-white text-sm font-semibold tracking-wide">
                            {card.name}
                          </p>
                        </div>
                      </div>

                      <div className="flex items-center gap-3">
                        <div className="text-right">
                          <p className="text-white/60 text-[9px] uppercase tracking-wider mb-0.5">
                            Expires
                          </p>
                          <p className="text-white text-sm font-semibold tracking-wide">
                            {card.expiryDate}
                          </p>
                        </div>
                        <button
                          onClick={() => copyCardNumber(card.cardNumber)}
                          className="p-2 bg-white/20 hover:bg-white/30 rounded-lg transition-colors"
                        >
                          {copiedCard === maskCardNumber(card.cardNumber) ? (
                            <Check className="w-4 h-4 text-white" />
                          ) : (
                            <Copy className="w-4 h-4 text-white/90" />
                          )}
                        </button>
                      </div>
                    </div>
                  </div>

                  {/* Card Details */}
                  <div className="p-4 border-t border-gray-200">
                    <div className="flex items-center justify-between mb-3">
                      <span className="text-sm font-medium text-gray-600">
                        Balance
                      </span>
                      <span className="text-black font-bold text-lg">
                        {showBalance ? formatCurrency(card.balance) : "••••"}
                      </span>
                    </div>
                    <div className="w-full bg-gray-200 rounded-full h-2 mb-3 overflow-hidden">
                      <div
                        className="h-full bg-black rounded-full transition-all duration-1000"
                        style={{
                          width: `${(card.balance / card.limit) * 100}%`,
                        }}
                      />
                    </div>
                    <div className="flex items-center justify-between text-xs text-gray-500">
                      <span>Limit: {formatCurrency(card.limit)}</span>
                      <span>
                        {Math.round((card.balance / card.limit) * 100)}%
                        Available
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Recent Transactions */}
          <div>
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-bold text-black">
                Recent Transactions
              </h2>
              <div className="flex items-center gap-2">
                <button className="p-3 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors">
                  <Search className="w-4 h-4 text-black" />
                </button>
                <button className="p-3 bg-white border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors">
                  <Filter className="w-4 h-4 text-black" />
                </button>
              </div>
            </div>

            <div className="bg-white border border-gray-200 rounded-lg overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full min-w-[640px]">
                  <thead className="bg-gray-50 border-b border-gray-200">
                    <tr>
                      <th className="text-left p-6 text-sm font-medium text-gray-600">
                        Transaction
                      </th>
                      <th className="text-left p-6 text-sm font-medium text-gray-600">
                        Date
                      </th>
                      <th className="text-right p-6 text-sm font-medium text-gray-600">
                        Amount
                      </th>
                      <th className="text-center p-6 text-sm font-medium text-gray-600">
                        Status
                      </th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-200">
                    {transactions.map((transaction) => (
                      <tr
                        key={transaction.id}
                        className="hover:bg-gray-50 transition-colors"
                      >
                        <td className="p-6">
                          <div className="flex items-center gap-4">
                            <div
                              className={`w-12 h-12 rounded-lg flex items-center justify-center border ${
                                transaction.type === "topup"
                                  ? "bg-gray-100 border-gray-200"
                                  : "bg-gray-100 border-gray-200"
                              }`}
                            >
                              {transaction.type === "topup" ? (
                                <ArrowDownLeft className="w-6 h-6 text-black" />
                              ) : (
                                <ArrowUpRight className="w-6 h-6 text-black" />
                              )}
                            </div>
                            <div>
                              <p className="font-semibold text-black mb-1">
                                {transaction.description}
                              </p>
                              <p className="text-sm text-gray-600">
                                {transaction.merchant}
                              </p>
                            </div>
                          </div>
                        </td>
                        <td className="p-6 text-sm text-gray-600">
                          {transaction.date}
                        </td>
                        <td
                          className={`p-6 text-right font-bold text-lg ${
                            transaction.amount > 0
                              ? "text-black"
                              : "text-black"
                          }`}
                        >
                          {transaction.amount > 0 ? "+" : ""}
                          {formatCurrency(transaction.amount)}
                        </td>
                        <td className="p-6 text-center">
                          <span
                            className={`px-4 py-2 rounded-full text-xs font-semibold border inline-block ${
                              transaction.status === "completed"
                                ? "bg-gray-100 border-gray-200 text-gray-700"
                                : "bg-gray-100 border-gray-200 text-gray-700"
                            }`}
                          >
                            {transaction.status === "completed"
                              ? "✓ Completed"
                              : "⏳ Pending"}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}
